INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('enough', 'op', 86, 'OP', '足够；充分', 'as much or as many as needed', 'We have enough bread for everyone.', '我们有足够的面包给每个人。', '[{"w":"almost","def":"almost: 相关的动作或关系词","vs":"与 enough 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"almost\" / \"enough\" 的替换练习"},{"w":"even","def":"even: 可帮助扩展句型的基础词","vs":"与 enough 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"even\" / \"enough\" 的替换练习"},{"w":"not","def":"not: 同一组 Basic English 操作词","vs":"与 enough 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"not\" / \"enough\" 的替换练习"}]'),
  ('even', 'op', 87, 'OP', '甚至；平的；均匀的', 'including something surprising, or level and equal', 'Even a small child can see the moon.', '甚至小孩子也能看到月亮。', '[{"w":"enough","def":"enough: 相关的动作或关系词","vs":"与 even 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"enough\" / \"even\" 的替换练习"},{"w":"not","def":"not: 可帮助扩展句型的基础词","vs":"与 even 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"not\" / \"even\" 的替换练习"},{"w":"only","def":"only: 同一组 Basic English 操作词","vs":"与 even 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"only\" / \"even\" 的替换练习"}]'),
  ('not', 'op', 88, 'OP', '不；表示否定', 'make a word, phrase, or statement negative', 'This road is not safe at night.', '这条路夜里不安全。', '[{"w":"even","def":"even: 相关的动作或关系词","vs":"与 not 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"even\" / \"not\" 的替换练习"},{"w":"only","def":"only: 可帮助扩展句型的基础词","vs":"与 not 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"only\" / \"not\" 的替换练习"},{"w":"quite","def":"quite: 同一组 Basic English 操作词","vs":"与 not 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"quite\" / \"not\" 的替换练习"}]'),
  ('only', 'op', 89, 'OP', '只有；仅仅', 'no more than or no one except', 'Only one train goes north today.', '今天只有一班火车向北开。', '[{"w":"not","def":"not: 相关的动作或关系词","vs":"与 only 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"not\" / \"only\" 的替换练习"},{"w":"quite","def":"quite: 可帮助扩展句型的基础词","vs":"与 only 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"quite\" / \"only\" 的替换练习"},{"w":"so","def":"so: 同一组 Basic English 操作词","vs":"与 only 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"so\" / \"only\" 的替换练习"}]'),
  ('quite', 'op', 90, 'OP', '相当；完全；十分', 'to a noticeable or complete degree', 'The room is quite warm now.', '房间现在相当暖和。', '[{"w":"only","def":"only: 相关的动作或关系词","vs":"与 quite 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"only\" / \"quite\" 的替换练习"},{"w":"so","def":"so: 可帮助扩展句型的基础词","vs":"与 quite 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"so\" / \"quite\" 的替换练习"},{"w":"very","def":"very: 同一组 Basic English 操作词","vs":"与 quite 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"very\" / \"quite\" 的替换练习"}]');
